})

console.log(salesDataTable,'salesDataTable')

function formatIndianNumber(value, includeDecimals = true) {
    if (value === null || value === undefined) return '';
    const x = value.toString().split('.');
    let lastThree = x[0].substring(x[0].length - 3);
    const otherNumbers = x[0].substring(0, x[0].length - 3);
    if (otherNumbers !== '') lastThree = ',' + lastThree;
    const formattedNumber = otherNumbers.replace(/\B(?=(\d{2})+(?!\d))/g, ',') + lastThree;
    return includeDecimals && x.length > 1 ? formattedNumber + '.' + x[1] : formattedNumber;
}

onMounted(async() => {
    salesCount.fetch()
    salesTotal.fetch()
    salesOpenCount.fetch()
    salesOpenTotal.fetch()
    await salesDataTable.fetch()
})

const getAbbreviatedName = (name) =>{
    if (!name) return '';
    const nameParts = name.split(' ');
    const initials = nameParts.map(part => part.charAt(0).toUpperCase()).join('');
    return initials;
}

